class Solution:
    def guessNumber(self, n: int) -> int:
        def search(lo, hi):
            if lo > hi:
                return -1
            mid = (lo + hi) // 2
            r = guess(mid)
            if r == 0:
                return mid
            if r < 0:
                return search(lo, mid - 1)
            return search(mid + 1, hi)
        return search(1, n)

