class Solution:
    def guessNumber(self, n: int) -> int:
        lo, hi = 1, n
        while lo <= hi:
            mid = lo + (hi - lo) // 2
            r = guess(mid)
            if r == 0:
                return mid
            if r < 0:
                hi = mid - 1
            else:
                lo = mid + 1
        return -1

